section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/spatial-ui-patterns.json",
  "title": "Spatial UI Patterns",
  "type": "object",
  "required": [
    "artefact_id",
    "feature_id",
    "anchoring_strategy",
    "window_layout",
    "platform_targets",
    "hig_compliance",
    "motion_sickness_mitigation",
    "evidence",
    "owner",
    "status",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "feature_id": {
      "type": "string",
      "description": "feature_id",
      "minLength": 1
    },
    "anchoring_strategy": {
      "type": "string",
      "description": "anchoring_strategy",
      "minLength": 1
    },
    "window_layout": {
      "type": "string",
      "description": "window_layout",
      "minLength": 1
    },
    "platform_targets": {
      "type": "array",
      "description": "platform_targets (array)",
      "minItems": 1
    },
    "hig_compliance": {
      "type": "string",
      "description": "hig_compliance",
      "minLength": 1
    },
    "motion_sickness_mitigation": {
      "type": "string",
      "description": "motion_sickness_mitigation",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
